const input = $json.body || $json || {};

function clean(value) {
  return String(value ?? '').replace(/\s+/g, ' ').trim();
}

function normalized(value) {
  return clean(value)
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .toLowerCase();
}

function pick(source, keys) {
  if (!source || typeof source !== 'object' || Array.isArray(source)) return '';
  for (const key of keys) {
    if (source[key] !== undefined && source[key] !== null && clean(source[key])) {
      return clean(source[key]);
    }
  }
  return '';
}

function normalizeStage(value) {
  const text = normalized(value);
  if (!text) return '';
  if (/infantil|preescolar/.test(text)) return 'Infantil';
  if (/primaria/.test(text)) return 'Primaria';
  if (/secundaria/.test(text)) return 'Secundaria';
  if (/bachillerato/.test(text)) return 'Bachillerato';
  return clean(value);
}

function normalizeSubject(value) {
  const text = normalized(value);
  if (!text) return '';
  if (/educacion fisica|ed\.? fisica/.test(text)) return 'Ed. Fisica';
  if (/matematic/.test(text)) return 'Matematicas';
  if (/lengua|lenguaje/.test(text)) return 'Lengua';
  if (/ciencias?/.test(text)) return 'Ciencias';
  if (/historia/.test(text)) return 'Historia';
  if (/ingles/.test(text)) return 'Ingles';
  if (/musica/.test(text)) return 'Musica';
  if (/arte/.test(text)) return 'Arte';
  return clean(value);
}

function normalizeDuration(value) {
  const text = normalized(value);
  if (!text) return '';
  const match = text.match(/\b(\d{1,3})\s*(min|minutos|hora|horas)\b/);
  if (!match) return clean(value);
  const amount = Number(match[1]);
  if (!Number.isFinite(amount)) return clean(value);
  if (match[2].startsWith('hora')) {
    return amount === 1 ? '1 hora' : `${amount} horas`;
  }
  return `${amount} min`;
}

const rawMessage = clean(input.message || input.text);
const embeddedContextMatch = rawMessage.match(/^\[CONTEXTO PRE-CARGADO:\s*([^\]]+)\]/i);
const embeddedContext = {};
if (embeddedContextMatch) {
  const block = clean(embeddedContextMatch[1]);
  for (const piece of block.split('|')) {
    const [rawKey, ...rest] = piece.split(':');
    const key = normalized(rawKey);
    const value = clean(rest.join(':'));
    if (!value) continue;
    if (['nivel', 'stage', 'etapa', 'level'].includes(key)) embeddedContext.stage = value;
    if (['subject', 'materia', 'asignatura'].includes(key)) embeddedContext.subject = value;
    if (key.startsWith('duraci') || ['duration', 'tiempo'].includes(key)) embeddedContext.duration = value;
  }
}

const context = input.context && typeof input.context === 'object' && !Array.isArray(input.context)
  ? input.context
  : {};

const profile = {
  stage: normalizeStage(pick(context, ['stage', 'nivel', 'etapa', 'level']) || embeddedContext.stage),
  subject: normalizeSubject(pick(context, ['subject', 'materia', 'asignatura']) || embeddedContext.subject),
  duration: normalizeDuration(pick(context, ['duration', 'duracion', 'tiempo']) || embeddedContext.duration)
};

return [{
  json: {
    sessionId: clean(input.sessionId),
    message: clean(rawMessage.replace(/^\[CONTEXTO PRE-CARGADO:[^\]]+\]\s*/i, '')),
    profile,
    requestedAt: clean(input.timestamp) || new Date().toISOString()
  }
}];

const input = { ...$json };

function clean(value) {
  return String(value ?? '').replace(/\s+/g, ' ').trim();
}

const hasProfile = Object.values(input.profile || {}).some((value) => clean(value));
const missingFields = ['stage', 'subject', 'duration'].filter((key) => !clean(input.profile?.[key]));
const hasUsefulRequest = Boolean(clean(input.message) || hasProfile);

let type = 'clarification';
let message = '';
let shouldCallModel = true;

if (!clean(input.sessionId)) {
  type = 'error';
  message = 'sessionId es obligatorio para usar el asistente docente.';
  shouldCallModel = false;
} else if (!hasUsefulRequest) {
  type = 'clarification';
  message = 'Necesito un mensaje o contexto educativo para ayudarte a planificar la actividad.';
  shouldCallModel = false;
} else if (!clean(input.message) && missingFields.length > 0) {
  type = 'clarification';
  message = `Necesito estos datos para seguir: ${missingFields.join(', ')}.`;
  shouldCallModel = false;
}

return [{
  json: {
    ...input,
    missingFields,
    shouldCallModel,
    validationType: type,
    validationMessage: message
  }
}];

const config = {
  lmStudioUrl: 'https://realtor-employee-cafe-offshore.trycloudflare.com/v1/chat/completions',
  lmStudioKey: 'CHANGE_ME_LM_STUDIO_TOKEN',
  lmModel: 'google/gemma-4-e2b',
  timeout: 45000,
  supabaseUrl: 'https://zvsfkafxicgutlrotugz.supabase.co/rest/v1/sessions?on_conflict=session_id',
  supabaseKey: 'sb_publishable_-PEWfNAp_rfgoSMZZHhHyQ_iKr2qsTn'
};

return [{ json: { ...$json, config } }];

